  // Parse level tags: [LEVEL:+xp] or [LEVEL:+level]
  cleanText = cleanText.replace(/\[LEVEL:\+(\d+)\]/gi, (_m, nStr: string) => {
    const n = parseInt(nStr, 10);
    if (!isNaN(n) && n > 0) {
      // Heuristic: if the number is small (≤20), treat as level increase;
      // otherwise treat as XP gain. Both can apply simultaneously.
      if (n <= 20) {
        levelChanges.push({ xpDelta: 0, levelDelta: n });
      } else {
        levelChanges.push({ xpDelta: n, levelDelta: 0 });
      }
    }
    return "";
  });

  return { cleanText, mutations, skillChanges, levelChanges };
}

