function makeCharacter(partial: Partial<Character> = {}): Character {
  return {
    id: "c1",
    name: "Elara",
    description: "A wandering mage.",
    personality: "Curious and blunt.",
    scenario: "A tavern at dusk.",
    firstMes: "Hello, {{user}}, I am {{char}}.",
    mesExample: "",
