import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";

import { getSetting, setSetting } from "../../db/repositories/settingsRepo";
import { FONT_SCALES, useSettingsStore, type Theme } from "../../stores/settingsStore";
import type { SupportedLanguage } from "../../i18n";

const DEFAULT_QUICK_ACTIONS = [
  "🔍 Prozkoumat",
  "⚔️ Zaútočit",
  "💬 Promluvit",
  "🧪 Použít předmět",
  "📜 Použít dovednost",
];

export function AppearancePanel() {
  const { t } = useTranslation("settings");
  const { theme, language, fontScale, setTheme, setLanguage, setFontScale } = useSettingsStore();
  const [quickActionsText, setQuickActionsText] = useState("");
  const [quickSaved, setQuickSaved] = useState(false);

  useEffect(() => {
    void (async () => {
      const raw = await getSetting("quick_actions");
      if (raw) {
        try {
          const parsed = JSON.parse(raw);
          if (Array.isArray(parsed) && parsed.length > 0) {
            setQuickActionsText(parsed.join("\n"));
            return;
          }
        } catch { /* fallback */ }
      }
      setQuickActionsText(DEFAULT_QUICK_ACTIONS.join("\n"));
    })();
  }, []);

  const handleSaveQuickActions = async () => {
    const lines = quickActionsText
      .split("\n")
      .map((l) => l.trim())
      .filter((l) => l.length > 0);
    const json = JSON.stringify(lines.length > 0 ? lines : DEFAULT_QUICK_ACTIONS);
    await setSetting("quick_actions", json);
    setQuickSaved(true);
    setTimeout(() => setQuickSaved(false), 2000);
  };

  return (
    <section
      className="rounded-[var(--radius-lg)] border p-5"
      style={{ borderColor: "var(--color-border)", backgroundColor: "var(--color-surface)" }}
    >
      <h2 className="mb-4 font-[var(--font-display)] text-lg">{t("sections.appearance")}</h2>

      <div className="flex flex-col gap-4 sm:flex-row sm:gap-10">
        <div>
          <span className="mb-2 block text-xs font-medium uppercase tracking-wide" style={{ color: "var(--color-text-faint)" }}>
            {t("appearance.language")}
          </span>
          <div className="inline-flex overflow-hidden rounded-[var(--radius-sm)] border" style={{ borderColor: "var(--color-border-strong)" }}>
            {(["cs", "en"] as SupportedLanguage[]).map((lang) => (
              <button
                key={lang}
                type="button"
                onClick={() => void setLanguage(lang)}
                aria-pressed={language === lang}
                className="px-3 py-1.5 text-sm transition-colors"
                style={{
                  backgroundColor: language === lang ? "var(--color-accent)" : "transparent",
                  color: language === lang ? "var(--color-accent-contrast)" : "var(--color-text-muted)",
                }}
              >
                {lang === "cs" ? t("appearance.languageCs") : t("appearance.languageEn")}
              </button>
            ))}
          </div>
        </div>

        <div>
          <span className="mb-2 block text-xs font-medium uppercase tracking-wide" style={{ color: "var(--color-text-faint)" }}>
            {t("appearance.theme")}
          </span>
          <div className="inline-flex overflow-hidden rounded-[var(--radius-sm)] border" style={{ borderColor: "var(--color-border-strong)" }}>
            {(["dark", "light"] as Theme[]).map((th) => (
              <button
                key={th}
                type="button"
                onClick={() => void setTheme(th)}
                aria-pressed={theme === th}
                className="px-3 py-1.5 text-sm transition-colors"
                style={{
                  backgroundColor: theme === th ? "var(--color-accent)" : "transparent",
                  color: theme === th ? "var(--color-accent-contrast)" : "var(--color-text-muted)",
                }}
              >
                {th === "dark" ? t("appearance.themeDark") : t("appearance.themeLight")}
              </button>
            ))}
          </div>
        </div>

        <div>
          <span className="mb-2 block text-xs font-medium uppercase tracking-wide" style={{ color: "var(--color-text-faint)" }}>
            {t("appearance.fontSize")}
          </span>
          <div className="inline-flex overflow-hidden rounded-[var(--radius-sm)] border" style={{ borderColor: "var(--color-border-strong)" }}>
            {FONT_SCALES.map((scale) => (
              <button
                key={scale}
                type="button"
                onClick={() => void setFontScale(scale)}
                aria-pressed={fontScale === scale}
                title={`${scale} %`}
                className="px-3 py-1.5 transition-colors"
                style={{
                  // Preview each step at its own size; sized in px on purpose
                  // so the labels don't rescale when the root font changes.
                  fontSize: `${(14 * scale) / 100}px`,
                  backgroundColor: fontScale === scale ? "var(--color-accent)" : "transparent",
                  color: fontScale === scale ? "var(--color-accent-contrast)" : "var(--color-text-muted)",
                }}
              >
                A
              </button>
            ))}
          </div>
        </div>
      </div>

      <h3 className="mb-1 mt-6 text-sm font-medium">{t("appearance.quickActionsTitle")}</h3>
      <p className="mb-2 text-xs" style={{ color: "var(--color-text-faint)" }}>
        {t("appearance.quickActionsHint")}
      </p>
      <textarea
        className="w-full max-w-md resize-y rounded-[var(--radius-sm)] border px-3 py-2 text-sm"
        style={{
          backgroundColor: "var(--color-surface-2)",
          borderColor: "var(--color-border-strong)",
          color: "var(--color-text)",
        }}
        rows={5}
        value={quickActionsText}
        onChange={(e) => setQuickActionsText(e.target.value)}
      />
      <div className="mt-2 flex items-center gap-3">
        <button
          type="button"
          onClick={() => void handleSaveQuickActions()}
          className="rounded-[var(--radius-sm)] px-3 py-1.5 text-sm"
          style={{ backgroundColor: "var(--color-accent)", color: "var(--color-accent-contrast)" }}
        >
          {t("common:actions.save")}
        </button>
        {quickSaved && (
          <span className="text-xs" style={{ color: "var(--color-success)" }}>
            {t("memory.saved")}
          </span>
        )}
      </div>
    </section>
  );
}

